import React from 'react';
import { UIShell as CarbonUIShell } from '@carbon/react';

const UIShell = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonUIShell
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonUIShell>
    );
};

UIShell.defaultProps = {
    className: ''
};

export default UIShell;
